const fs = require('fs');
const crypto = require('crypto');

// Ensure the music directory exists
const musicDir = '/files/music';
if (!fs.existsSync(musicDir)) {
  fs.mkdirSync(musicDir, { recursive: true });
}

const item = $input.first();

// Try common binary field names
const binaryKey = item.binary?.file
  ? 'file'
  : item.binary?.data
  ? 'data'
  : Object.keys(item.binary || {})[0] || null;

if (!binaryKey || !item.binary[binaryKey]) {
  throw new Error('No binary file data found in request. Send file as multipart/form-data field named "file".');
}

const binary = item.binary[binaryKey];
const uuid = crypto.randomUUID();
const destPath = `${musicDir}/${uuid}.mp3`;

// binary.data is a base64-encoded string in n8n
const buffer = Buffer.from(binary.data, 'base64');
fs.writeFileSync(destPath, buffer);

const originalName = binary.fileName || binary.filename || 'music.mp3';

return [{ json: { file_id: uuid, original_name: originalName, path: destPath } }];
